(function($){var settings=[];var setting={};var element;var loader;$.fn.repeater=function(options,params){if(typeof options==="object"){element=$(this);var currentId=element.attr("id");var instance={id:currentId,endpoint:"",type:"GET",mappingFunction:function(data){return""},success:function(e,data){return},fail:function(error){return},messageNoResult:"No records returned",cssClassNoResult:"text-center",messageLoading:"Loading data...",params:{},refresh:refresh,sortKey:null,sortType:null,async:false};setting=$.extend(true,instance,options);settings.push(setting);refresh();return element}if(typeof options==="string"){element=$(this);var currentId=element.attr("id");if(options=="refresh"){var foundSettings=$.grep(settings,(function(e){return e.id==currentId}));var foundSetting=foundSettings[0];if(params!=undefined)foundSetting.params=params;if(foundSettings.length>0){setting=$.extend(true,foundSettings[0],options);settings.push(setting);refresh();return element}}if(options=="clear"){element.empty()}}return element};function refresh(){generateElementBody(null,0);var parameters={context:document.body,dataType:"json",type:setting.type,async:setting.async,statusCode:{404:function(data){generateElementBody(data,404)},500:function(data){generateElementBody(data,500)},200:function(data){generateElementBody(data,200)}},complete:function(data){setting.success()}};if(setting.type.toUpperCase()=="GET"){var queryString="";try{queryString=jQuery.param(setting.params)}catch(exception){queryString=""}parameters.url=setting.endpoint+"?"+queryString}else if(setting.type.toUpperCase()=="POST"){parameters.url=setting.endpoint;parameters.data=setting.params}else{setting.fail("Unsupported call type");return}$.ajax(parameters)}function generateElementBody(data,code){var html="";element.empty();if(code==0){html='<div class="'+setting.cssClassNoResult+'">'+"    <strong>"+setting.messageLoading+"</strong>"+"</div>"}if(code==404){html='<div class="'+setting.cssClassNoResult+'">'+"    No data"+"</div>"}if(code==500){html='<div class="'+setting.cssClassNoResult+'">'+"    Error occured"+"</div>"}if(code==200){try{html=setting.mappingFunction(data)}catch(exception){html=""}if(html==""){html='<div class="'+setting.cssClassNoResult+'">'+"    <strong>"+setting.messageNoResult+"</strong>"+"</div>"}}element.html(html)}})(jQuery);